@namespace Lumeo
@typeparam TItem
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (Context is not null && Context.IsLoading)
{
    <tbody data-slot="datagrid-body" class="@CssClass" @attributes="AdditionalAttributes">
        @{
            // Context.VisibleColumns is already filtered + cached at the grid level.
            var visibleColumns = Context.VisibleColumns;
            var fallbackCellCount = visibleColumns.Count > 0 ? visibleColumns.Count : (SkeletonRowCount > 0 ? 4 : 4);
        }
        @for (var i = 0; i < SkeletonRowCount; i++)
        {
            <tr class="border-b border-border/40">
                @if (Context.SelectionMode != DataGridSelectionMode.None)
                {
                    <td class="px-3 py-2 w-10">
                        <Skeleton Class="h-4 w-4 rounded" />
                    </td>
                }
                @if (HasDetailTemplate)
                {
                    <td class="px-1 py-2 w-8">
                        <Skeleton Class="h-4 w-4 rounded" />
                    </td>
                }
                @if (visibleColumns.Count > 0)
                {
                    @foreach (var column in visibleColumns)
                    {
                        <td class="px-3 py-2">
                            <Skeleton Class="h-4 w-full rounded" />
                        </td>
                    }
                }
                else
                {
                    @for (var j = 0; j < fallbackCellCount; j++)
                    {
                        <td class="px-3 py-2">
                            <Skeleton Class="h-4 w-full rounded" />
                        </td>
                    }
                }
            </tr>
        }
    </tbody>
}
else if (Context is not null && Context.IsTreeGrid)
{
    <tbody data-slot="datagrid-body" class="@CssClass" @attributes="AdditionalAttributes">
        @if (Context.DisplayedItems.Count == 0)
        {
            <tr>
                <td colspan="@ColSpan" class="px-3 py-8 text-center text-muted-foreground">
                    @if (EmptyContent is not null) { @EmptyContent }
                    else
                    {
                        <div class="flex flex-col items-center gap-2">
                            <Blazicon Svg="Lucide.Inbox" class="h-8 w-8 text-muted-foreground/50" />
                            <span class="text-sm">@L["DataGrid.NoData"]</span>
                        </div>
                    }
                </td>
            </tr>
        }
        else
        {
            var ti = 0;
            foreach (var item in Context.DisplayedItems)
            {
                <DataGridRow @key="DataGridRowKeys.KeyFor(item)" TItem="TItem"
                             Item="item"
                             RowIndex="ti"
                             DetailTemplate="DetailTemplate"
                             OnContextMenu="OnContextMenu" />
                ti++;
            }
        }
    </tbody>
}
else if (Context is not null && Context.GroupTree is not null && Context.GroupTree.Count > 0)
{
    // Multi-level grouping: render a nested forest of group rows.
    RenderFragment<DataGridGroupNode<TItem>>? renderNode = null;
    renderNode = node => __builder =>
    {
        var expanded = Context.IsGroupPathExpanded(node.Path);
        <DataGridGroupRow @key="@("g:" + node.Path)" TItem="TItem"
                          GroupKey="@node.Key"
                          Count="@node.TotalCount"
                          Level="@node.Level"
                          IsExpanded="@expanded"
                          Aggregates="@node.Aggregates"
                          ColSpan="@ColSpan"
                          OnToggle="@(() => Context.ToggleGroupPath(node.Path))" />
        if (expanded)
        {
            if (node.Children.Count > 0)
            {
                foreach (var child in node.Children)
                {
                    @renderNode!(child)
                }
            }
            else
            {
                var li = 0;
                foreach (var item in node.Items)
                {
                    <DataGridRow @key="DataGridRowKeys.KeyFor(item)" TItem="TItem"
                                 Item="item"
                                 RowIndex="li"
                                 DetailTemplate="DetailTemplate"
                                 OnContextMenu="OnContextMenu" />
                    li++;
                }
            }
        }
    };
    <tbody data-slot="datagrid-body" class="@CssClass" @attributes="AdditionalAttributes">
        @foreach (var root in Context.GroupTree)
        {
            @renderNode(root)
        }
    </tbody>
}
else if (Context is not null && Context.IsGrouped && Context.GroupedSections is not null && Context.GroupedSections.Count > 0)
{
    <tbody data-slot="datagrid-body" class="@CssClass" @attributes="AdditionalAttributes">
        @foreach (var grp in Context.GroupedSections)
        {
            var groupKey = grp.Key;
            var expanded = Context.IsGroupExpanded(groupKey);
            <DataGridGroupRow @key="groupKey" TItem="TItem"
                              GroupKey="@groupKey"
                              Count="@grp.TotalCount"
                              IsExpanded="@expanded"
                              Aggregates="@grp.Aggregates"
                              ColSpan="@ColSpan"
                              OnToggle="@(() => Context.ToggleGroupExpand(groupKey))" />
            if (expanded)
            {
                var grpIndex = 0;
                foreach (var item in grp.Items)
                {
                    <DataGridRow @key="DataGridRowKeys.KeyFor(item)" TItem="TItem"
                                 Item="item"
                                 RowIndex="grpIndex"
                                 DetailTemplate="DetailTemplate"
                                 OnContextMenu="OnContextMenu" />
                    grpIndex++;
                }
            }
        }
    </tbody>
}
else if (Context is not null && Context.DisplayedItems.Count == 0)
{
    <tbody data-slot="datagrid-body" class="@CssClass" @attributes="AdditionalAttributes">
        <tr>
            <td colspan="@ColSpan" class="px-3 py-8 text-center text-muted-foreground">
                @if (EmptyContent is not null)
                {
                    @EmptyContent
                }
                else
                {
                    <div class="flex flex-col items-center gap-2">
                        <Blazicon Svg="Lucide.Inbox" class="h-8 w-8 text-muted-foreground/50" />
                        <span class="text-sm">@L["DataGrid.NoData"]</span>
                    </div>
                }
            </td>
        </tr>
    </tbody>
}
else if (Context is not null && ServerVirtualizationProvider is not null)
{
    @* Virtualised server mode: rows are fetched in scroll-driven windows
       via ItemsProvider, so the in-memory list is empty until the user
       scrolls. SpacerElement="tr" is non-negotiable inside <tbody>. *@
    <tbody data-slot="datagrid-body" class="@CssClass" @attributes="AdditionalAttributes">
        <Virtualize @ref="_virtualize" TItem="IndexedItem"
                    ItemsProvider="ServerVirtualizationProvider"
                    Context="entry"
                    SpacerElement="tr"
                    ItemSize="@VirtualItemSize"
                    OverscanCount="@VirtualOverscanCount">
            <ItemContent>
                <DataGridRow TItem="TItem"
                             Item="entry.Item"
                             RowIndex="entry.Index"
                             DetailTemplate="DetailTemplate"
                             OnContextMenu="OnContextMenu" />
            </ItemContent>
            <Placeholder>
                <tr class="border-b border-border/40">
                    <td colspan="@ColSpan" class="px-3 py-2">
                        <Skeleton Class="h-4 w-full rounded" />
                    </td>
                </tr>
            </Placeholder>
        </Virtualize>
    </tbody>
}
else if (Context is not null && UseVirtualization)
{
    <tbody data-slot="datagrid-body" class="@CssClass" @attributes="AdditionalAttributes">
        @* SpacerElement="tr" is required: <Virtualize> defaults to <div>
           spacers, but <div> is invalid as a direct child of <tbody> and the
           browser hoists it out of the table, breaking layout. *@
        <Virtualize Items="@_indexedItems" Context="entry"
                    SpacerElement="tr"
                    ItemSize="@VirtualItemSize"
                    OverscanCount="@VirtualOverscanCount">
            <DataGridRow TItem="TItem"
                         Item="entry.Item"
                         RowIndex="entry.Index"
                         DetailTemplate="DetailTemplate"
                         OnContextMenu="OnContextMenu" />
        </Virtualize>
    </tbody>
}
else if (Context is not null)
{
    <tbody data-slot="datagrid-body" class="@CssClass" @attributes="AdditionalAttributes">
        @if (Context.IsGrouped && Context.GroupedSections is not null)
        {
            @foreach (var grp in Context.GroupedSections)
            {
                var groupKey = grp.Key;
                var expanded = Context.IsGroupExpanded(groupKey);
                <DataGridGroupRow @key="groupKey" TItem="TItem"
                                  GroupKey="@groupKey"
                                  Count="@grp.TotalCount"
                                  IsExpanded="@expanded"
                                  ColSpan="@ColSpan"
                                  OnToggle="@(() => Context.ToggleGroupExpand(groupKey))" />
                if (expanded)
                {
                    var grpIndex = 0;
                    foreach (var item in grp.Items)
                    {
                        <DataGridRow @key="DataGridRowKeys.KeyFor(item)" TItem="TItem"
                                     Item="item"
                                     RowIndex="grpIndex"
                                     DetailTemplate="DetailTemplate"
                                     OnContextMenu="OnContextMenu" />
                        grpIndex++;
                    }
                }
            }
        }
        else
        {
            var idx = 0;
            foreach (var item in Context.DisplayedItems)
            {
                <DataGridRow @key="DataGridRowKeys.KeyFor(item)" TItem="TItem"
                             Item="item"
                             RowIndex="idx"
                             DetailTemplate="DetailTemplate"
                             OnContextMenu="OnContextMenu" />
                idx++;
            }
        }
    </tbody>
}

@code {
    [CascadingParameter] private DataGridContext<TItem>? Context { get; set; }
    [Parameter] public RenderFragment<TItem>? DetailTemplate { get; set; }
    [Parameter] public RenderFragment? EmptyContent { get; set; }
    [Parameter] public bool UseVirtualization { get; set; }
    [Parameter] public float VirtualItemSize { get; set; } = 41f;
    [Parameter] public int VirtualOverscanCount { get; set; } = 3;
    /// <summary>When set, switches the body to ItemsProvider-mode
    /// virtualisation (window-fetched server scrolling). Null disables.</summary>
    [Parameter] public Microsoft.AspNetCore.Components.Web.Virtualization.ItemsProviderDelegate<IndexedItem>? ServerVirtualizationProvider { get; set; }
    [Parameter] public bool HasDetailTemplate { get; set; }
    [Parameter] public int SkeletonRowCount { get; set; } = 5;
    [Parameter] public EventCallback<(TItem, double, double)> OnContextMenu { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"{Class}".Trim();

    private List<IndexedItem> _indexedItems = new();
    private Microsoft.AspNetCore.Components.Web.Virtualization.Virtualize<IndexedItem>? _virtualize;

    /// <summary>Tells the inner <c>Virtualize</c> component to discard its
    /// window cache and refetch via <see cref="ServerVirtualizationProvider"/>.
    /// No-op when not in ItemsProvider mode (no virtualizer in tree).</summary>
    public Task RefreshVirtualizeAsync() =>
        _virtualize is not null ? _virtualize.RefreshDataAsync() : Task.CompletedTask;

    protected override void OnParametersSet()
    {
        if (UseVirtualization && Context is not null)
        {
            _indexedItems = Context.DisplayedItems
                .Select((item, idx) => new IndexedItem(item, idx))
                .ToList();
        }
    }

    private int ColSpan
    {
        get
        {
            var count = Context?.VisibleColumns.Count ?? 1;
            if (Context?.SelectionMode != DataGridSelectionMode.None) count++;
            if (HasDetailTemplate) count++;
            return count;
        }
    }

    public record IndexedItem(TItem Item, int Index);
}

@namespace Lumeo
@typeparam TItem

<td data-slot="datagrid-cell" class="@CssClass" style="@PinStyle"
    id="@CellId"
    role="gridcell"
    aria-colindex="@AriaColIndex"
    aria-readonly="@AriaReadonly"
    tabindex="@TabIndexValue"
    @onclick="HandleClick"
    @ondblclick="HandleDoubleClick"
    @onkeydown="HandleCellKeyDown"
    @attributes="AdditionalAttributes">
    @if (_isEditing && Column.EditTemplate is not null)
    {
        @Column.EditTemplate(_editContext!)
    }
    else if (_isEditing)
    {
        <input class="w-full bg-transparent border-none outline-none text-sm"
               value="@_editValue"
               @oninput="OnEditInput"
               @onblur="CommitEdit"
               @onkeydown="OnEditKeyDown" />
    }
    else if (Column.CellTemplate is not null)
    {
        @Column.CellTemplate(Item)
    }
    else if (IsBatchDirty)
    {
        @* Batch-edit: show the buffered value (overrides the row's current
           value) so the user sees what will be saved. *@
        @FormatBatchValue(Context!.GetBatchValue(Item, Column))
    }
    else
    {
        @Column.GetFormattedValue(Item, Context?.Culture ?? System.Globalization.CultureInfo.CurrentCulture)
    }
</td>

@code {
    [CascadingParameter] private DataGridContext<TItem>? Context { get; set; }
    [Parameter] public TItem Item { get; set; } = default!;
    [Parameter] public DataGridColumn<TItem> Column { get; set; } = default!;
    /// <summary>0-based index of the owning row within DisplayedItems (non-grouped).</summary>
    [Parameter] public int RowIndex { get; set; }
    /// <summary>0-based index of this column within the visible columns.</summary>
    [Parameter] public int ColumnIndex { get; set; }
    /// <summary>1-based ARIA column index (includes any leading non-data columns).</summary>
    [Parameter] public int AriaColIndex { get; set; }
    /// <summary>Whether this cell participates in roving-tabindex keyboard navigation.
    /// False in grouped mode where row indices are not globally unique.</summary>
    [Parameter] public bool Navigable { get; set; } = true;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _isEditing;
    private string? _editValue;
    private object? _originalValue;
    private CellEditContext<TItem>? _editContext;

    // --- Keyboard navigation / ARIA (rc.32) ---
    // Cell-level inline editing applies in both Cell and Batch modes — the
    // difference is where the commit lands (immediate vs buffered).
    private bool CellEditable =>
        (Context?.EditMode == DataGridEditMode.Cell || Context?.EditMode == DataGridEditMode.Batch)
        && Column.Field is not null;

    // True when this (row, column) currently carries a buffered batch edit.
    // Drives the dirty marker (left border accent) and the display override.
    private bool IsBatchDirty =>
        Context?.IsBatchEdit == true
        && Column.Field is not null
        && Context.IsCellDirty(Item, Column.Field!);

    private string? AriaReadonly => CellEditable ? null : "true";

    private string FormatBatchValue(object? value)
    {
        if (value is null) return "";
        var culture = Context?.Culture ?? System.Globalization.CultureInfo.CurrentCulture;
        if (value is IFormattable f)
            return f.ToString(Column.Format, culture);
        return value.ToString() ?? "";
    }

    private string? CellId =>
        Navigable && Context is not null ? $"{Context.GridId}-cell-{RowIndex}-{ColumnIndex}" : null;

    // Roving tabindex: exactly one cell across header + body carries tabindex="0".
    private int TabIndexValue =>
        Navigable && Context is not null && Context.FocusedRow == RowIndex && Context.FocusedCol == ColumnIndex
            ? 0 : -1;

    private async Task HandleCellKeyDown(KeyboardEventArgs e)
    {
        if (!Navigable || Context is null) return;

        // Enter / F2 → enter edit mode for this cell (when editable). Edit-mode key
        // handling (Escape/Enter/Tab) lives in the <input>'s own OnEditKeyDown.
        if ((e.Key == "Enter" || e.Key == "F2") && CellEditable && !_isEditing)
        {
            StartEdit();
            return;
        }

        // Navigation / selection keys → delegate to the grid.
        await Context.OnCellKeyDown(RowIndex, ColumnIndex, e);
    }

    // Memoization mirror of DataGridRow.CssClass: 10k cells × N renders worth
    // of string.Join allocations. The key carries every input that influences
    // the result; we recompute only when something actually changes.
    private (object Key, string Css)? _cssCache;

    private bool IsRowSelected =>
        Context is not null && Context.SelectionMode != DataGridSelectionMode.None && Context.IsRowSelected(Item);

    private string CssClass
    {
        get
        {
            var cellClass = Column.CellClass?.Invoke(Item);
            var pin = Column.Pin;
            var dirty = IsBatchDirty;
            var selected = IsRowSelected;
            var striped = Context?.Striped == true;
            var hoverable = Context?.Hoverable == true;
            var key = (pin, dirty, selected, striped, hoverable, RowIndex % 2, Column.CssClass, cellClass, Class);
            if (_cssCache is { } c && c.Key.Equals(key)) return c.Css;

            // Pinned cells need an opaque background so the scrolling
            // un-pinned cells don't show through behind them. When the grid
            // is Striped we must mirror the row's alternating background:
            // even rows get bg-muted/30 (matching [&_tbody>tr:nth-child(even)]:bg-muted/30
            // on the root), odd rows get bg-background. Without this the pinned
            // column would render as a flat bg-card block breaking the stripe pattern.
            // When not Striped a flat bg-card is fine (matches the card surface).
            // group-hover/row:bg-muted/50 re-applies the row hover tint on the pinned
            // cell (the td's own bg otherwise prevents the tr hover from showing through).
            // The selection highlight is layered on top via PinStyle (background-image
            // linear-gradient) so it survives either stripe variant.
            var hoverClass = hoverable ? "group-hover/row:bg-muted/50" : null;
            // For pinned cells the actual background-color is set inline via
            // PinStyle — Tailwind v4's JIT can't see arbitrary classes built
            // through C# string interpolation, so `bg-[color-mix(...)]` never
            // produces a rule and the cell renders transparent. The class only
            // carries sticky positioning + hover behavior; PinStyle paints.
            string? pinClass = pin switch
            {
                PinDirection.Left or PinDirection.Right => $"sticky z-10 {hoverClass}",
                _ => null
            };
            var css = string.Join(" ", new[]
            {
                "px-3 py-2 text-sm",
                "outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
                pinClass,
                // Batch-edit dirty marker: subtle left border accent + warning
                // background tint. Uses the lumeo.css --color-warning token so
                // it stays theme-aware in dark mode.
                dirty ? "border-l-2 border-warning bg-warning/10" : null,
                Column.CssClass,
                cellClass,
                Class
            }.Where(s => !string.IsNullOrWhiteSpace(s)));
            _cssCache = (key, css);
            return css;
        }
    }

    private string PinStyle
    {
        get
        {
            string? offset = null;
            if (Column.Pin == PinDirection.Left && Context?.PinnedLeftOffsets.TryGetValue(Column.Id, out var leftOff) == true)
                offset = $"left: {leftOff}px;";
            else if (Column.Pin == PinDirection.Right && Context?.PinnedRightOffsets.TryGetValue(Column.Id, out var rightOff) == true)
                offset = $"right: {rightOff}px;";

            if (offset is null) return string.Empty;

            // OPAQUE background for pinned cells so scrolling non-pinned columns
            // don't bleed through. When the grid is Striped we mirror the row's
            // alternating bg via color-mix at runtime (Tailwind v4 can't see
            // dynamically-interpolated arbitrary classes, so we paint in inline
            // style instead). Non-striped → flat card.
            string bg;
            if (Context?.Striped == true && RowIndex % 2 == 1)
            {
                // 30% muted over card = exact visual of bg-muted/30 row stripe,
                // but rendered as a fully opaque single color.
                bg = " background-color: color-mix(in srgb, var(--color-card) 70%, var(--color-muted));";
            }
            else
            {
                bg = " background-color: var(--color-card);";
            }

            // Layer a primary/5 tint on top of the opaque pinned bg when the row
            // is selected — matches the row-level bg-primary/5 highlight so the
            // pinned column doesn't read as "not selected" mid-row.
            if (IsRowSelected)
            {
                return offset + bg + " background-image: linear-gradient(hsl(var(--primary) / 0.05), hsl(var(--primary) / 0.05));";
            }
            return offset + bg;
        }
    }

    private void HandleClick()
    {
        if (CellEditable && !_isEditing)
        {
            StartEdit();
        }
    }

    private void HandleDoubleClick()
    {
        if (CellEditable && !_isEditing)
        {
            StartEdit();
        }
    }

    private void StartEdit()
    {
        // In batch mode, seed from the pending buffer if there's one — otherwise
        // the user would have to retype an edit they just committed.
        _originalValue = Column.GetValue(Item);
        var seedValue = Context?.IsBatchEdit == true
            ? Context.GetBatchValue(Item, Column)
            : _originalValue;
        _editValue = seedValue?.ToString() ?? "";
        _editContext = new CellEditContext<TItem>
        {
            Item = Item,
            Column = Column,
            Value = seedValue,
            ValueChanged = () =>
            {
                _editValue = _editContext?.Value?.ToString();
                StateHasChanged();
            }
        };
        _isEditing = true;
    }

    private void OnEditInput(ChangeEventArgs e)
    {
        _editValue = e.Value?.ToString();
        if (_editContext is not null)
        {
            _editContext.Value = _editValue;
        }
    }

    private async Task OnEditKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await CommitEdit();
            // Excel-like: after committing, move focus down one row.
            if (Navigable && Context is not null)
            {
                await Context.OnCellKeyDown(RowIndex, ColumnIndex, new KeyboardEventArgs { Key = "ArrowDown" });
            }
        }
        else if (e.Key == "Escape")
        {
            CancelEdit();
            if (Navigable && Context is not null)
            {
                // Re-focus the cell <td> so arrow nav resumes immediately.
                await Context.OnCellKeyDown(RowIndex, ColumnIndex, new KeyboardEventArgs { Key = "Home" });
                await Context.OnCellKeyDown(RowIndex, ColumnIndex, new KeyboardEventArgs { Key = "End" });
            }
        }
        else if (e.Key == "Tab")
        {
            await CommitEdit();
            // Move to the next editable cell to the right (browser handles plain
            // Tab too, but committing first keeps state consistent).
            if (Navigable && Context is not null)
            {
                await Context.OnCellKeyDown(RowIndex, ColumnIndex, new KeyboardEventArgs { Key = "ArrowRight" });
            }
        }
    }

    private async Task CommitEdit()
    {
        if (!_isEditing) return;
        _isEditing = false;

        if (Context is null || Column.Field is null) return;

        // Batch mode → write into the pending-changes buffer; don't mutate the
        // row and don't fire OnCellEdit (that fires later on Save all via the
        // consumer's OnBatchSave handler).
        if (Context.IsBatchEdit)
        {
            Context.SetBatchValue(Item, Column, _editValue);
            return;
        }

        if (_editValue != _originalValue?.ToString())
        {
            var args = new CellEditEventArgs<TItem>(Item, Column.Field, _originalValue, _editValue);
            await Context.OnCellEdit.InvokeAsync(args);
        }
    }

    private void CancelEdit()
    {
        _isEditing = false;
        _editValue = null;
    }
}

using System.Collections.Concurrent;
using System.Globalization;
using System.Linq.Expressions;
using System.Reflection;
using Microsoft.AspNetCore.Components;

namespace Lumeo;

public class DataGridColumn<TItem>
{
    public string Id { get; set; } = Guid.NewGuid().ToString("N")[..8];
    public string? Title { get; set; }
    public string? Field { get; set; }
    public Func<TItem, object?>? FieldSelector { get; set; }
    public double? Width { get; set; }
    public double? MinWidth { get; set; }
    public double? MaxWidth { get; set; }
    public bool Sortable { get; set; }
    public bool Filterable { get; set; }
    public bool Pinnable { get; set; }
    public bool Resizable { get; set; } = true;
    public bool Visible { get; set; } = true;
    public bool Groupable { get; set; }
    /// <summary>
    /// Whether this column can be reordered via header drag-and-drop or the
    /// Toggle Columns menu arrows. When false, the column is pinned to its
    /// current position regardless of the grid-level <c>Reorderable</c> flag.
    /// Defaults to <c>true</c>.
    /// </summary>
    public bool Reorderable { get; set; } = true;
    public PinDirection Pin { get; set; } = PinDirection.None;
    public DataGridFilterType FilterType { get; set; } = DataGridFilterType.Text;
    public AggregateType Aggregate { get; set; } = AggregateType.None;
    public string? Format { get; set; }
    /// <summary>Optional .NET format string used by the footer aggregate strip — overrides
    /// the cell <see cref="Format"/> for the totals row (e.g. cell shows <c>"C2"</c> and
    /// totals show <c>"N0"</c>). When null the footer falls back to <see cref="Format"/>,
    /// then to the historic <c>"N2"</c> default.</summary>
    public string? FooterFormat { get; set; }
    /// <summary>Id of the <see cref="DataGridColumnGroup{TItem}"/> this column belongs to,
    /// when present. Drives the extra header row that spans grouped columns with a
    /// single labelled <c>th</c>. Null for ungrouped columns.</summary>
    public string? ColumnGroupId { get; set; }
    public string? CssClass { get; set; }
    public string? HeaderCssClass { get; set; }
    public RenderFragment<TItem>? CellTemplate { get; set; }
    public RenderFragment? HeaderTemplate { get; set; }
    public RenderFragment<CellEditContext<TItem>>? EditTemplate { get; set; }
    public Func<TItem, string>? CellClass { get; set; }
    public Comparison<object?>? CustomSort { get; set; }
    public List<FilterOption>? FilterOptions { get; set; }

    /// <summary>
    /// Optional whitelist of filter operators shown in the column filter UI.
    /// When null, the grid exposes the default set for the column's <see cref="FilterType"/>.
    /// When set, only operators present in this list are offered (still intersected with the
    /// built-in defaults so unsupported combinations are not surfaced accidentally).
    /// </summary>
    public List<FilterOperator>? Operators { get; set; }

    /// <summary>
    /// Optional custom filter UI for this column. When provided, the default filter body
    /// (operator + value inputs) is replaced with this render fragment, allowing the consumer
    /// to implement any filter experience (sliders, multi-selects, relative-date pickers, ...).
    /// The context exposes the current <see cref="FilterDescriptor"/> for the column
    /// (or null) and an Apply callback the consumer invokes to commit the filter.
    /// Passing null to Apply clears the filter.
    /// </summary>
    public RenderFragment<DataGridFilterTemplateContext>? FilterTemplate { get; set; }

    // Per-column cache of compiled getters, keyed by field name. A compiled
    // Func<TItem, object?> is ~10x faster than PropertyInfo.GetValue and the
    // delta matters: GetValue runs once per cell per render.
    //
    // Behavior preservation vs. the previous reflection-based path:
    //   * Unknown field on TItem → PropertyInfo.GetProperty(...) returned null and
    //     GetValue returned null. The compiled path mirrors this by caching a
    //     null delegate and returning null.
    //   * Nested paths (e.g. "Address.City") are supported with null-safe
    //     traversal: any null intermediate yields null instead of throwing
    //     NullReferenceException — the previous code would have thrown on
    //     nested paths since GetProperty doesn't traverse dots; this is a
    //     net behavior gain and does not regress any existing flat path.
    private readonly ConcurrentDictionary<string, Func<TItem, object?>?> _gettersByField = new(StringComparer.Ordinal);

    public object? GetValue(TItem item)
    {
        if (FieldSelector is not null) return FieldSelector(item);
        if (Field is null || item is null) return null;

        var getter = _gettersByField.GetOrAdd(Field, static f => BuildGetter(f));
        return getter?.Invoke(item);
    }

    private static Func<TItem, object?>? BuildGetter(string fieldPath)
    {
        var param = Expression.Parameter(typeof(TItem), "x");
        Expression current = param;
        var currentType = typeof(TItem);

        // Walk dotted segments, chaining .Property accesses. Track each segment
        // so we can guard against null intermediates with Expression.Condition.
        var segments = fieldPath.Split('.');
        var nullChecks = new List<Expression>();

        foreach (var segment in segments)
        {
            var prop = currentType.GetProperty(segment, BindingFlags.Public | BindingFlags.Instance);
            if (prop is null)
            {
                // Unknown property at any depth → match reflection's null return.
                return null;
            }

            // For reference-typed intermediates, add a null-check on the value
            // BEFORE we descend into it. Value-typed intermediates can't be null
            // (Nullable<T> is handled via .Value but is uncommon for these paths;
            // we leave that to ordinary access — matches old single-level behavior).
            if (!current.Type.IsValueType && !ReferenceEquals(current, param))
            {
                nullChecks.Add(Expression.Equal(current, Expression.Constant(null, current.Type)));
            }

            current = Expression.Property(current, prop);
            currentType = prop.PropertyType;
        }

        // Box the final value to object so the delegate returns object?.
        Expression body = currentType.IsValueType
            ? Expression.Convert(current, typeof(object))
            : current;

        // If we accumulated null-guards, fold them into a single short-circuit:
        // (intermediate1 == null || intermediate2 == null || ...) ? null : body
        if (nullChecks.Count > 0)
        {
            Expression anyNull = nullChecks[0];
            for (var i = 1; i < nullChecks.Count; i++)
                anyNull = Expression.OrElse(anyNull, nullChecks[i]);

            body = Expression.Condition(
                anyNull,
                Expression.Constant(null, typeof(object)),
                body);
        }

        return Expression.Lambda<Func<TItem, object?>>(body, param).Compile();
    }

    /// <summary>
    /// Formats a row's value for display, using <see cref="CultureInfo.CurrentCulture"/>
    /// so ASP.NET request localization affects dates/numbers automatically.
    /// </summary>
    public string GetFormattedValue(TItem item)
        => GetFormattedValue(item, CultureInfo.CurrentCulture);

    /// <summary>
    /// Formats a row's value for display using the supplied culture. Prefers
    /// <see cref="IFormattable"/> to guarantee culture-aware output for numbers
    /// and dates; falls back to <see cref="object.ToString"/> for other types.
    /// </summary>
    public string GetFormattedValue(TItem item, CultureInfo culture)
    {
        var value = GetValue(item);
        if (value is null) return "";
        if (value is IFormattable f)
            return f.ToString(Format, culture);
        return value.ToString() ?? "";
    }
}

