@code {
    [Parameter] public IReadOnlyList<DataGridColumn<TItem>> Columns { get; set; } = Array.Empty<DataGridColumn<TItem>>();
    [Parameter] public EventCallback<DataGridColumn<TItem>> OnColumnToggle { get; set; }
    [Parameter] public EventCallback<ColumnReorderEventArgs> OnColumnReorder { get; set; }
    [Parameter] public EventCallback<ColumnPinEventArgs> OnColumnPin { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"w-64 rounded-lg border border-border/40 bg-popover text-popover-foreground shadow-md {Class}".Trim();

    // Mutable buffer for SortableList. We keep it in sync with the readonly
    // Columns parameter; the drag callback runs locally on this buffer, then
    // we emit a single ColumnReorderEventArgs (oldIndex, newIndex) so the
    // parent's reorder pipeline stays the keyboard/UI source of truth.
    private List<DataGridColumn<TItem>> _buffer = new();
    private string? _openPinMenu;
    private bool _pinMenuClickOutsideRegistered;

    // Stable per-column IDs for click-outside registration.
    private string PinTriggerId(string columnId) => $"dg-pin-trigger-{columnId}";
    private string PinMenuId(string columnId) => $"dg-pin-menu-{columnId}";

    protected override void OnParametersSet()
    {
        _buffer = Columns.ToList();
    }

    private async Task ToggleColumn(DataGridColumn<TItem> column, bool visible)
    {
        column.Visible = visible;
        await OnColumnToggle.InvokeAsync(column);
    }

    private async Task HandleSortChanged(List<DataGridColumn<TItem>> reordered)
    {
        // Diff old -> new to recover the (oldIndex, newIndex) move. SortableList
        // performs a single Remove+Insert per drop, so exactly one column moved.
        var oldOrder = Columns.ToList();
        if (reordered.Count != oldOrder.Count) return;

        int movedNewIndex = -1;
        for (int i = 0; i < reordered.Count; i++)
        {
            if (!ReferenceEquals(reordered[i], oldOrder[i]))
            {
                movedNewIndex = i;
                break;
            }
        }
        if (movedNewIndex < 0) return;

        var moved = reordered[movedNewIndex];
        var oldIndex = oldOrder.FindIndex(c => ReferenceEquals(c, moved));
        if (oldIndex < 0 || oldIndex == movedNewIndex) return;

        _buffer = reordered;
        var args = new ColumnReorderEventArgs(moved.Id, oldIndex, movedNewIndex);
        await OnColumnReorder.InvokeAsync(args);
    }

    private async Task TogglePinMenu(string columnId)
    {
        if (_openPinMenu == columnId)
        {
            await ClosePinMenuAsync();
        }
        else
        {
            // Close any previously open menu first.
            if (_openPinMenu is not null)
                await ClosePinMenuAsync();

            _openPinMenu = columnId;
            StateHasChanged();
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_openPinMenu is not null && !_pinMenuClickOutsideRegistered)
        {
            var menuId = PinMenuId(_openPinMenu);
            var triggerId = PinTriggerId(_openPinMenu);
            try
            {
                await Interop.RegisterClickOutside(menuId, triggerId, async () =>
                {
                    _openPinMenu = null;
                    _pinMenuClickOutsideRegistered = false;
                    await InvokeAsync(StateHasChanged);
                });
                _pinMenuClickOutsideRegistered = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        else if (_openPinMenu is null && _pinMenuClickOutsideRegistered)
        {
            await UnregisterPinMenuClickOutsideAsync();
        }
    }

    private async Task ClosePinMenuAsync()
    {
        _openPinMenu = null;
        if (_pinMenuClickOutsideRegistered)
            await UnregisterPinMenuClickOutsideAsync();
        StateHasChanged();
    }

    private async Task UnregisterPinMenuClickOutsideAsync()
    {
        _pinMenuClickOutsideRegistered = false;
        // We need to unregister for each column; use a snapshot of the last open menu id.
        // Since _openPinMenu is already null here, iterate the column list and try all.
        foreach (var col in _buffer)
        {
            try { await Interop.UnregisterClickOutside(PinMenuId(col.Id)); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch { /* element may not have been registered */ }
        }
    }

    private void HandlePinMenuKeyDown(KeyboardEventArgs e, string columnId)
    {
        if (e.Key == "Escape" && _openPinMenu == columnId)
        {
            _ = ClosePinMenuAsync();
        }
    }

    private async Task PinColumn(DataGridColumn<TItem> column, PinDirection direction)
    {
        await ClosePinMenuAsync();
        await OnColumnPin.InvokeAsync(new ColumnPinEventArgs(column.Id, direction));
    }

    public async ValueTask DisposeAsync()
    {
        if (_pinMenuClickOutsideRegistered)
        {
            await UnregisterPinMenuClickOutsideAsync();
        }
    }
}

