@typeparam TItem
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<tr data-slot="datagrid-group-row" class="@CssClass"
    role="row"
    @onclick="Toggle" @attributes="AdditionalAttributes">
    <td colspan="@ColSpan" class="px-3 py-2 font-medium">
        @* The inner sticky div pins the group label to the left viewport
           edge during horizontal scroll so it's always readable. z-10 keeps
           it above regular body cells (z-10 on pinned cells, but the group row
           spans the whole width so normal cells are peers, not siblings here). *@
        <div class="sticky left-0 z-10 flex items-center gap-2" style="@IndentStyle">
            <button type="button" class="inline-flex items-center justify-center h-5 w-5 rounded hover:bg-muted focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1">
                <Blazicon Svg="Lucide.ChevronDown" class="@ChevronClasses" />
            </button>
            <span class="text-sm">@GroupKey</span>
            <span class="text-xs text-muted-foreground">@L[Lumeo.Services.Localization.LumeoPlurals.PluralKey(Count, "DataGrid.ItemsCount", System.Globalization.CultureInfo.CurrentUICulture), Count]</span>
            @if (Aggregates is { Count: > 0 })
            {
                <span class="ml-2 flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs text-muted-foreground font-normal">
                    @foreach (var agg in Aggregates)
                    {
                        var colTitle = ColumnTitle(agg.ColumnId);
                        <span>@(string.IsNullOrEmpty(colTitle) ? "" : colTitle + " ")@agg.Label: <span class="font-medium text-foreground">@agg.Value</span></span>
                    }
                </span>
            }
        </div>
    </td>
</tr>

@code {
    [CascadingParameter] private DataGridContext<TItem>? Context { get; set; }
    [Parameter] public string? GroupKey { get; set; }
    [Parameter] public int Count { get; set; }
    [Parameter] public bool IsExpanded { get; set; }
    [Parameter] public EventCallback OnToggle { get; set; }
    [Parameter] public int ColSpan { get; set; } = 1;
    /// <summary>Nesting depth for multi-level grouping (0 = top level). Controls indentation.</summary>
    [Parameter] public int Level { get; set; }
    /// <summary>Per-group aggregate strip rendered next to the group label.</summary>
    [Parameter] public IReadOnlyList<DataGridGroupAggregate>? Aggregates { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"bg-muted/40 border-b border-border/40 cursor-pointer hover:bg-muted/60 transition-colors {Class}".Trim();

    // Single ChevronDown that rotates -90deg when collapsed; smooth like Accordion.
    private string ChevronClasses =>
        $"h-4 w-4 shrink-0 text-muted-foreground transition-transform duration-200{(IsExpanded ? "" : " -rotate-90")}";

    private string? IndentStyle => Level > 0 ? $"padding-left: {0.75 + Level * 1.25:0.##}rem;" : null;

    private string ColumnTitle(string columnId)
    {
        var col = Context?.Columns.FirstOrDefault(c => c.Id == columnId);
        return col?.Title ?? col?.Field ?? "";
    }

    private async Task Toggle()
    {
        await OnToggle.InvokeAsync();
    }
}

@namespace Lumeo
@typeparam TItem

<thead data-slot="datagrid-header" class="@CssClass" @attributes="AdditionalAttributes">
    @* When the grid has DataGridColumnGroups, render a parent header row above the data
       row. Each registered group spans its child columns via colspan; columns without a
       group get a blank cell so visual alignment stays intact. The data row that follows
       carries the actual sort / filter / resize handles per column. *@
    @if (Context is not null && HasColumnGroups)
    {
        <tr role="row" aria-rowindex="1" class="border-b border-border/40">
            @if (Context.RowReorderable) { <th class="bg-muted/30"></th> }
            @if (Context.SelectionMode != DataGridSelectionMode.None) { <th class="bg-muted/30"></th> }
            @if (HasDetailTemplate) { <th class="bg-muted/30"></th> }
            @foreach (var run in GetGroupHeaderRuns())
            {
                if (run.Info is { } info)
                {
                    <th colspan="@run.Span"
                        class="@($"px-3 py-2 text-xs font-semibold text-foreground/80 bg-muted/40 text-center border-x border-border/40 {info.HeaderClass}".Trim())">
                        @info.Label
                    </th>
                }
                else
                {
                    @* Ungrouped column(s) — colspan over the run keeps the parent row aligned. *@
                    <th colspan="@run.Span" class="bg-muted/30"></th>
                }
            }
            @if (Context.EditMode == DataGridEditMode.Row) { <th class="bg-muted/30"></th> }
        </tr>
    }
    <tr role="row" aria-rowindex="@(HasColumnGroups ? 2 : 1)">
        @* Row reorder handle column *@
        @if (Context?.RowReorderable == true)
        {
            <th role="columnheader" class="px-1 py-2 w-8 bg-muted/30"></th>
        }

        @if (Context?.SelectionMode == DataGridSelectionMode.Multiple)
        {
            @* Sticky left-0 when any column is pinned so it stays aligned with
               the sticky body selection cells during horizontal scroll. z-30 keeps
               it above z-20 pinned header cells (which are themselves z-20).
               When sticky, use bg-muted (opaque) so scrolling columns don't bleed
               through the semi-transparent bg-muted/30. *@
            <th role="columnheader" class="@(Context.HasPinnedLeft ? "px-3 py-2 w-10 bg-muted sticky left-0 z-30" : "px-3 py-2 w-10 bg-muted/30")">
                <Checkbox Checked="@AllSelected"
                          IsIndeterminate="@SomeSelected"
                          CheckedChanged="@OnSelectAllChanged" />
            </th>
        }
        else if (Context?.SelectionMode == DataGridSelectionMode.Single)
        {
            <th role="columnheader" class="@(Context.HasPinnedLeft ? "px-3 py-2 w-10 bg-muted sticky left-0 z-30" : "px-3 py-2 w-10 bg-muted/30")"></th>
        }

        @if (HasDetailTemplate)
        {
            <th role="columnheader" class="px-1 py-2 w-8 bg-muted/30"></th>
        }

        @if (Context is not null)
        {
            var colIndex = 0;
            var leading = LeadingColumnCount;
            @foreach (var column in Context.VisibleColumns)
            {
                var idx = colIndex;
                var sortDir = GetSortDirection(column);
                var hasFilter = HasFilter(column);
                var isFilterOpen = ActiveFilterColumn == column.Field;
                <DataGridHeaderCell @key="column.Id" TItem="TItem"
                                    Column="column"
                                    ColumnIndex="idx"
                                    AriaColIndex="@(leading + idx + 1)"
                                    SortDirection="sortDir"
                                    HasActiveFilter="hasFilter"
                                    IsFilterOpen="isFilterOpen"
                                    Reorderable="Reorderable"
                                    SortPriority="GetSortPriority(column)"
                                    TotalSortCount="GetTotalSortCount()"
                                    OnFilterToggle="@(() => OnFilterToggle.InvokeAsync(column.Field))"
                                    OnFilterApply="OnFilterApply"
                                    OnColumnReorder="OnColumnReorder" />
                colIndex++;
            }
        }

        @* Row edit action column placeholder in header *@
        @if (Context?.EditMode == DataGridEditMode.Row)
        {
            <th role="columnheader" class="px-3 py-2 w-10 bg-muted/30"></th>
        }
    </tr>
</thead>

@code {
    [CascadingParameter] private DataGridContext<TItem>? Context { get; set; }
    [Parameter] public bool HasDetailTemplate { get; set; }
    [Parameter] public string? ActiveFilterColumn { get; set; }
    [Parameter] public bool Reorderable { get; set; }
    [Parameter] public EventCallback<string?> OnFilterToggle { get; set; }
    [Parameter] public EventCallback<FilterApplyEventArgs> OnFilterApply { get; set; }
    [Parameter] public EventCallback<ColumnReorderEventArgs> OnColumnReorder { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"sticky top-0 z-20 bg-card [&_tr]:border-b [&_tr]:border-border/40 {Class}".Trim();

    /// <summary>Number of non-data leading columns (reorder handle, selection,
    /// detail toggle) rendered before the first data column. Used to offset
    /// 1-based <c>aria-colindex</c> values.</summary>
    private int LeadingColumnCount
    {
        get
        {
            var n = 0;
            if (Context?.RowReorderable == true) n++;
            if (Context?.SelectionMode != DataGridSelectionMode.None) n++;
            if (HasDetailTemplate) n++;
            return n;
        }
    }

    // Count-based comparison breaks under SelectionKeySelector + server-mode:
    // _selectedItems may carry rows from other pages, so a single visible row
    // with one cross-page selection would falsely report all-selected. Probe
    // each DisplayedItem via Context.IsRowSelected — that's also how individual
    // row checkboxes decide their state, so the header now matches them.
    private bool AllSelected
    {
        get
        {
            if (Context is null || Context.DisplayedItems.Count == 0) return false;
            foreach (var item in Context.DisplayedItems)
                if (!Context.IsRowSelected(item)) return false;
            return true;
        }
    }

    private bool SomeSelected
    {
        get
        {
            if (Context is null || Context.DisplayedItems.Count == 0) return false;
            bool anySelected = false, anyUnselected = false;
            foreach (var item in Context.DisplayedItems)
            {
                if (Context.IsRowSelected(item)) anySelected = true;
                else anyUnselected = true;
                if (anySelected && anyUnselected) return true;
            }
            return false;
        }
    }

    private SortDirection GetSortDirection(DataGridColumn<TItem> column)
    {
        if (Context is null || column.Field is null) return SortDirection.None;
        var sort = Context.Sorts.FirstOrDefault(s => s.Field == column.Field);
        return sort?.Direction ?? SortDirection.None;
    }

    private bool HasFilter(DataGridColumn<TItem> column)
    {
        if (Context is null || column.Field is null) return false;
        return Context.Filters.Any(f => f.Field == column.Field);
    }

    private int GetSortPriority(DataGridColumn<TItem> column)
    {
        if (Context is null || column.Field is null) return 0;
        var idx = Context.Sorts.FindIndex(s => s.Field == column.Field && s.Direction != SortDirection.None);
        return idx >= 0 ? idx + 1 : 0;
    }

    private int GetTotalSortCount() => Context?.Sorts.Count(s => s.Direction != SortDirection.None) ?? 0;

    private bool HasColumnGroups
        => Context is not null
           && Context.ColumnGroups.Count > 0
           && Context.VisibleColumns.Any(c => c.ColumnGroupId is not null);

    // A contiguous run of visible columns that all share the same ColumnGroupId.
    // Info is the resolved group metadata (null for the "ungrouped" runs). Span is
    // the colspan to emit on the parent <th>.
    private record GroupHeaderRun(DataGridColumnGroupInfo? Info, int Span);

    // Compute the parent-row cells in one pass over VisibleColumns. Each maximal run
    // of consecutive columns with the same ColumnGroupId collapses into one cell.
    private IEnumerable<GroupHeaderRun> GetGroupHeaderRuns()
    {
        if (Context is null) yield break;
        var groupsById = Context.ColumnGroups.ToDictionary(g => g.Id);
        string? currentId = null;
        DataGridColumnGroupInfo? currentInfo = null;
        var span = 0;
        foreach (var col in Context.VisibleColumns)
        {
            if (col.ColumnGroupId == currentId)
            {
                span++;
                continue;
            }
            if (span > 0)
            {
                yield return new GroupHeaderRun(currentInfo, span);
            }
            currentId = col.ColumnGroupId;
            currentInfo = currentId is not null && groupsById.TryGetValue(currentId, out var info) ? info : null;
            span = 1;
        }
        if (span > 0)
        {
            yield return new GroupHeaderRun(currentInfo, span);
        }
    }

    private void OnSelectAllChanged(bool value)
    {
        if (Context is null) return;
        if (value)
            Context.SelectAll();
        else
            Context.ClearSelection();
    }
}

@namespace Lumeo
@typeparam TItem
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<th data-slot="datagrid-header-cell" class="@CssClass" style="@StyleString"
    id="@CellId"
    data-col-id="@Column.Id"
    role="columnheader"
    aria-colindex="@AriaColIndex"
    aria-sort="@AriaSort"
    tabindex="@TabIndexValue"
    @onkeydown="HandleKeyDown"
    draggable="@(IsDraggable ? "true" : "false")"
    @ondragstart="HandleDragStart"
    @ondragend="HandleDragEnd"
    @ondragover="HandleDragOver"
    @ondragover:preventDefault="true"
    @ondrop="HandleDrop"
    @ondragenter="HandleDragEnter"
    @ondragleave="HandleDragLeave"
    @attributes="AdditionalAttributes">
    <div class="flex items-center gap-1">
        @if (Column.HeaderTemplate is not null)
        {
            @Column.HeaderTemplate
        }
        else
        {
            <button type="button"
                    class="flex items-center gap-1 select-none rounded focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 @(Column.Sortable ? "cursor-pointer hover:text-foreground" : "cursor-default")"
                    @onclick="HandleSort"
                    disabled="@(!Column.Sortable)">
                <span>@(Column.Title ?? Column.Field ?? "")</span>
                @if (Column.Sortable && SortDirection != SortDirection.None)
                {
                    @if (SortDirection == SortDirection.Ascending)
                    {
                        <Blazicon Svg="Lucide.ArrowUp" class="h-3.5 w-3.5" />
                    }
                    else
                    {
                        <Blazicon Svg="Lucide.ArrowDown" class="h-3.5 w-3.5" />
                    }
                    @if (TotalSortCount > 1 && SortPriority > 0)
                    {
                        <span class="flex items-center justify-center h-3.5 w-3.5 rounded-full bg-primary text-primary-foreground text-[9px] font-bold leading-none">@SortPriority</span>
                    }
                }
                else if (Column.Sortable)
                {
                    <Blazicon Svg="Lucide.ArrowUpDown" class="h-3.5 w-3.5 opacity-30" />
                }
            </button>
        }

        @* 2.2.2: visible drag-to-group affordance on columns that can be
           grouped. Without this, users had to try each column header to
           discover which ones supported drag-into-panel — draggable="true"
           on its own gave no visual cue. Mirrors the filter button's
           opacity-on-hover pattern; hidden when ShowGroupPanel is off (no
           point advertising drag-to-group when there's nowhere to drop). *@
        @if (Context?.ShowGroupPanel == true && Column.Groupable)
        {
            <Tooltip>
                <TooltipTrigger AsChild>
                    <ChildContentSlot Context="slot">
                        <span class="inline-flex items-center justify-center h-5 w-5 rounded text-muted-foreground opacity-0 group-hover/th:opacity-100 transition-opacity cursor-grab"
                              aria-label="@L["DataGrid.DragToGroup"]"
                              @attributes="slot.Attributes">
                            <Blazicon Svg="Lucide.Group" class="h-3 w-3" />
                        </span>
                    </ChildContentSlot>
                </TooltipTrigger>
                <TooltipContent>@L["DataGrid.DragToGroup"]</TooltipContent>
            </Tooltip>
        }
        @if (Column.Filterable)
        {
            <button type="button"
                    id="@_filterTriggerId"
                    class="inline-flex items-center justify-center h-5 w-5 rounded hover:bg-muted/60 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 @(HasActiveFilter ? "text-primary" : "text-muted-foreground opacity-0 group-hover/th:opacity-100")"
                    @onclick="ToggleFilter"
                    @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ListFilter" class="h-3 w-3" />
            </button>
        }
    </div>

    @if (IsFilterOpen && Column.Filterable)
    {
        @* Rendered with position:fixed and pinned to the trigger via
           Interop.PositionFixed (JS reads the trigger's getBoundingClientRect
           on open + on scroll/resize). Was previously position:absolute relative
           to the <th> which extended the grid's overflow:auto scrollWidth on the
           rightmost columns and made a phantom horizontal scrollbar appear when
           opening the filter. Floating-UI-style positioning sidesteps that
           entirely: the popover lives in the same DOM subtree but its layout
           box doesn't touch the scroll container. *@
        <div id="@_filterContentId" style="position: fixed; z-index: 50;">
            <DataGridColumnFilter TItem="TItem"
                                  Column="Column"
                                  FilterOptions="Column.FilterOptions"
                                  CurrentFilter="@CurrentFilter"
                                  OnApply="HandleFilterApply" />
        </div>
    }

    @if (Column.Resizable)
    {
        @* No Blazor pointerdown binding here — the JS listener attached via
           RegisterColumnResize() in OnAfterRenderAsync owns this event end to
           end (capture, move tracking via setPointerCapture, prevent the page
           from initiating a touch-scroll, commit on pointerup). Wiring a
           Blazor handler too would double-fire the pointerdown handling and
           recreate the lazy-register race from before. *@
        <div id="@_resizeHandleId"
             class="absolute right-0 top-0 bottom-0 w-1 cursor-col-resize hover:bg-primary/30 active:bg-primary/50"
             style="touch-action: none;"></div>
    }

    @if (_isDragOver && EffectiveReorderable && _dropSide is not null)
    {
        @* Drop indicator: a 4px vertical bar with primary glow that
           materializes between the dragged column and its prospective
           neighbour. Centred over the gap (translate -50%) so the bar
           sits ON the seam, not flush with the column edge — much
           easier for users to read as a slot marker than the older
           0.5px hairline. *@
        <div class="lumeo-datagrid-drop-indicator absolute top-0 bottom-0 w-1 bg-primary rounded-full pointer-events-none shadow-[0_0_8px_color-mix(in_oklab,var(--primary)_70%,transparent)]"
             style="@(_dropSide == "left" ? "left: 0; transform: translateX(-50%);" : "right: 0; transform: translateX(50%);") z-index: 10;"></div>
    }
</th>

@code {
    [CascadingParameter] private DataGridContext<TItem>? Context { get; set; }
    [CascadingParameter] private DataGrid<TItem>? ParentGrid { get; set; }
    [CascadingParameter] private DataGridDragState? DragState { get; set; }
    @* Inject the interface, not the concrete service, so tests can substitute
       a TrackingInteropService for the interop surface — every method used by
       this component (PositionFixed, RegisterClickOutside, RegisterColumnResize,
       …) is on the interface, so the switch is a pure DI tidy-up. *@
    [Inject] private IComponentInteropService Interop { get; set; } = default!;

    [Parameter] public DataGridColumn<TItem> Column { get; set; } = default!;
    [Parameter] public int ColumnIndex { get; set; }
    /// <summary>1-based ARIA column index (includes any leading non-data columns).</summary>
    [Parameter] public int AriaColIndex { get; set; }
    [Parameter] public SortDirection SortDirection { get; set; } = SortDirection.None;
    [Parameter] public bool HasActiveFilter { get; set; }
    [Parameter] public bool IsFilterOpen { get; set; }
    [Parameter] public bool Reorderable { get; set; }
    [Parameter] public EventCallback OnFilterToggle { get; set; }
    [Parameter] public EventCallback<FilterApplyEventArgs> OnFilterApply { get; set; }
    [Parameter] public EventCallback<ColumnReorderEventArgs> OnColumnReorder { get; set; }
    [Parameter] public int SortPriority { get; set; }
    [Parameter] public int TotalSortCount { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Keyboard navigation / ARIA (rc.32) ---
    private string? CellId => Context is null ? null : $"{Context.GridId}-cell-h-{ColumnIndex}";

    private string? AriaSort => Column.Sortable
        ? SortDirection switch
        {
            SortDirection.Ascending => "ascending",
            SortDirection.Descending => "descending",
            _ => "none"
        }
        : null;

    // Roving tabindex: exactly one header/body cell carries tabindex="0".
    private int TabIndexValue =>
        Context is not null && Context.FocusedRow == -1 && Context.FocusedCol == ColumnIndex ? 0 : -1;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // Note: we intentionally do NOT preventDefault here. Doing it conditionally
        // per-key in Blazor requires the directive value to be known at render time,
        // which would also block Tab from leaving the grid. Arrow keys may scroll the
        // container a little, but FocusElement() scrolls the target cell back into
        // view, so the net effect is correct.
        if (Context is null) return;

        if ((e.Key == "Enter" || e.Key == " " || e.Key == "Spacebar") && Column.Sortable)
        {
            await HandleSort();
            return;
        }

        await Context.OnHeaderKeyDown(ColumnIndex, e);
    }

    private FilterDescriptor? CurrentFilter =>
        Column?.Field is null || Context is null
            ? null
            : Context.Filters.FirstOrDefault(f => f.Field == Column.Field);

    private string _resizeHandleId = $"dg-resize-{Guid.NewGuid():N}";
    private bool _resizeRegistered;
    private bool _isDragOver;
    private string? _dropSide; // "left" or "right" — where the drop indicator is rendered

    // Filter popover positioning (2.1.2): the filter content is rendered with
    // position:fixed and pinned to the trigger via JS-computed coords from
    // getBoundingClientRect, matching the pattern in PopoverContent. Stable IDs
    // are needed so the JS positioner can find both elements and so click-outside
    // can exclude the trigger from its dismiss target list.
    private readonly string _filterTriggerId = $"dg-filter-trigger-{Guid.NewGuid():N}";
    private readonly string _filterContentId = $"dg-filter-content-{Guid.NewGuid():N}";
    private bool _filterPositionRegistered;

    /// <summary>
    /// Drag-reorder is only active when both the grid-level <c>Reorderable</c>
    /// flag and the per-column <c>Reorderable</c> flag are true.
    /// </summary>
    private bool EffectiveReorderable => Reorderable && Column.Reorderable;

    /// <summary>True when this header is the source of an in-flight column
    /// drag (the dragstart fired here and dragend / drop hasn't yet). Used
    /// to dim the source th so the user can see which column is moving.</summary>
    private bool IsDragSource =>
        DragState?.SourceColumnId is { } src && src == Column.Id;

    /// <summary>True when this header is HTML5-draggable. Two reasons to drag a
    /// header: reorder columns (Reorderable, drop on another header) or add the
    /// column as a new grouping level (Groupable, drop on the group panel —
    /// rc.41). The two pathways share <see cref="DataGridDragState"/> for the
    /// source-column record; drop targets decide which action to take.</summary>
    private bool IsDraggable =>
        EffectiveReorderable
        || (Context?.ShowGroupPanel == true && Column.Groupable);

    private string CssClass
    {
        get
        {
            var pinClass = Column.Pin switch
            {
                PinDirection.Left => "sticky z-20 bg-muted",
                PinDirection.Right => "sticky z-20 bg-muted",
                _ => "bg-muted/30"
            };
            return string.Join(" ", new[]
            {
                "group/th relative px-3 py-2 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider",
                "outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
                pinClass,
                // cursor-grab signals drag-affordance both for reorder AND for drag-to-group
                // (Groupable + ShowGroupPanel) — previously only the reorder case got it,
                // leaving Groupable-only columns with the default arrow cursor that hid
                // the drag-into-panel UX from users (2.2.2).
                IsDraggable ? "cursor-grab" : null,
                // Dim the dragged source header so users see at a glance which
                // column is moving. Pairs with the drop indicator on the target
                // to make the gesture's two endpoints visually distinct.
                IsDragSource ? "opacity-40 transition-opacity" : null,
                Column.HeaderCssClass,
                Class
            }.Where(s => !string.IsNullOrWhiteSpace(s)));
        }
    }

    private string? StyleString
    {
        get
        {
            var parts = new List<string>();
            if (Column.Width.HasValue)
            {
                parts.Add($"width: {Column.Width.Value}px");
                parts.Add($"min-width: {Column.Width.Value}px");
            }
            if (Column.Pin == PinDirection.Left && Context?.PinnedLeftOffsets.TryGetValue(Column.Id, out var leftOff) == true)
                parts.Add($"left: {leftOff}px");
            else if (Column.Pin == PinDirection.Right && Context?.PinnedRightOffsets.TryGetValue(Column.Id, out var rightOff) == true)
                parts.Add($"right: {rightOff}px");
            return parts.Count > 0 ? string.Join("; ", parts) + ";" : null;
        }
    }

    private async Task HandleSort()
    {
        if (!Column.Sortable || Context is null || Column.Field is null) return;

        var newDirection = SortDirection switch
        {
            SortDirection.None => SortDirection.Ascending,
            SortDirection.Ascending => SortDirection.Descending,
            SortDirection.Descending => SortDirection.None,
            _ => SortDirection.None
        };

        await Context.OnSort.InvokeAsync(new SortDescriptor(Column.Field, newDirection));
    }

    private async Task ToggleFilter()
    {
        await OnFilterToggle.InvokeAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Resize: register the JS pointer listeners ON the resize handle the
        // moment it's in the DOM. Lazy-registering inside OnResizeStart meant
        // the FIRST pointerdown ran the Blazor handler (which then asked JS to
        // wire up its own pointerdown listener) — but that listener wasn't
        // attached yet at the time of the originating event, so the first
        // drag attempt was a no-op. Users had to release and press again
        // before resize actually started. Registering on firstRender flips
        // that: by the time the user's first pointerdown lands, the JS
        // handler is already listening.
        // Re-check on every render — not just firstRender — so columns whose
        // Resizable flag flips on after mount (e.g. parent unlocks edit mode)
        // still pick up the listener. _resizeRegistered short-circuits when
        // the handler is already attached, so the cost is one bool check per
        // render.
        if (Column.Resizable && !_resizeRegistered)
        {
            await EnsureResizeRegistered();
        }
        else if (!Column.Resizable && _resizeRegistered)
        {
            // Column flipped Resizable true → false. The resize-handle div is
            // gone from the DOM (the @if (Column.Resizable) gate above) but
            // the JS pointer listener it was tied to stays attached to a
            // detached element until we unregister it. More importantly,
            // _resizeRegistered would otherwise stay true and a later
            // false → true flip wouldn't re-call EnsureResizeRegistered —
            // the newly-rendered handle would never receive a listener and
            // resizing would silently stop working (Codex review on #46).
            try { await Interop.UnregisterColumnResize(_resizeHandleId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _resizeRegistered = false;
        }

        if (!Column.Filterable) return;

        if (IsFilterOpen && !_filterPositionRegistered)
        {
            // Pin the filter content (position:fixed) to the trigger button's
            // viewport rect. The "start" align + "bottom" side mirror the
            // previous absolute top-full left-0 layout. JS handles flip if the
            // popover would overflow the viewport (e.g. last row on a tall
            // grid) and follows the trigger on scroll/resize.
            await Interop.PositionFixed(_filterContentId, _filterTriggerId, align: "start", matchWidth: false, side: "bottom");
            // Click-outside dismiss — explicitly exclude the trigger so the
            // toggle button doesn't immediately close-then-reopen on click.
            // Closing routes through OnFilterToggle (the same callback the
            // button uses) so parent state stays consistent.
            await Interop.RegisterClickOutside(_filterContentId, _filterTriggerId, async () =>
            {
                await OnFilterToggle.InvokeAsync();
                await InvokeAsync(StateHasChanged);
            });
            _filterPositionRegistered = true;
        }
        else if (!IsFilterOpen && _filterPositionRegistered)
        {
            await CleanupFilterPosition();
        }
    }

    private async Task CleanupFilterPosition()
    {
        try { await Interop.UnpositionFixed(_filterContentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_filterContentId); } catch (JSDisconnectedException) { }
        _filterPositionRegistered = false;
    }

    private async Task HandleFilterApply(FilterDescriptor? descriptor)
    {
        var args = new FilterApplyEventArgs(Column.Field, descriptor);
        await OnFilterApply.InvokeAsync(args);
    }

    // Register-once helper. Called from OnAfterRenderAsync(firstRender) so the
    // JS pointerdown listener is live before the user's first drag attempt.
    // The previous lazy-on-first-pointerdown path is gone — that handler's
    // sole job was registration, and it lost the originating pointerdown.
    private async Task EnsureResizeRegistered()
    {
        if (_resizeRegistered) return;
        // JS drags the header + body cells in the DOM directly (smooth, no
        // Blazor round-trips per pixel) and invokes the commit callback with
        // the final width on pointerup.
        await Interop.RegisterColumnResize(
            _resizeHandleId,
            Column.MinWidth ?? 50,
            Column.MaxWidth,
            async finalWidth =>
            {
                ParentGrid?.UpdateColumnWidth(Column.Id, finalWidth);
                await InvokeAsync(StateHasChanged);
            });
        _resizeRegistered = true;
    }

    // --- Column Drag & Drop Reordering ---
    //
    // Drag state is held by an instance-bound DataGridDragState cascaded from
    // the owning DataGrid<TItem>. Replaces the previous static-class holder
    // which was process-global and cross-talked between grid instances on the
    // same page (drag started in grid A, dropped on grid B → grid B applied
    // grid A's source index). Drop handler verifies SourceGridId matches via
    // DragState.IsOwnDragColumn, otherwise the drop is rejected.

    private void HandleDragStart(DragEventArgs e)
    {
        // rc.41: also start the drag when the column is Groupable + ShowGroupPanel
        // (drag target = the group panel, not another header). The single
        // StartColumnDrag call covers both code paths — reorder vs group is
        // decided at the drop site.
        if (!IsDraggable || DragState is null) return;
        DragState.StartColumnDrag(ColumnIndex, Column.Id);
    }

    private void HandleDragEnd(DragEventArgs e)
    {
        // Fires on the SOURCE element regardless of whether the drop
        // succeeded (drop target → ResetColumn already called) or was
        // cancelled (Esc, drop outside any target). The handler itself is
        // intentionally a no-op when there's no leftover state — but its
        // presence triggers a Blazor re-render of the source cell, which
        // clears the opacity-40 source-dim that IsDragSource toggled on.
        // Defensive ResetColumn covers the cancel path where no drop ran.
        if (DragState is not null && DragState.SourceColumnId == Column.Id)
        {
            DragState.ResetColumn();
        }
    }

    private void HandleDragOver(DragEventArgs e)
    {
        if (!EffectiveReorderable || DragState is null) return;
        if (!DragState.IsOwnDragColumn(ColumnIndex)) return;
        if (DragState.SourceColumnId == Column.Id) return;
        // Choose the drop side based on drag direction:
        // dragging from a lower index → drop AFTER this column (right edge).
        // dragging from a higher index → drop BEFORE this column (left edge).
        var src = DragState.SourceColumnIndex;
        _dropSide = src < ColumnIndex ? "right" : "left";
    }

    private void HandleDragEnter(DragEventArgs e)
    {
        if (!EffectiveReorderable || DragState is null) return;
        if (!DragState.IsOwnDragColumn(ColumnIndex)) return;
        if (DragState.SourceColumnId == Column.Id) return;
        _isDragOver = true;
        var src = DragState.SourceColumnIndex;
        _dropSide = src >= 0 && src < ColumnIndex ? "right" : "left";
    }

    private void HandleDragLeave(DragEventArgs e)
    {
        _isDragOver = false;
        _dropSide = null;
    }

    private async Task HandleDrop(DragEventArgs e)
    {
        _isDragOver = false;
        _dropSide = null;
        if (!EffectiveReorderable || DragState is null) return;

        // Reject drops from drags that originated in a different grid instance.
        if (!DragState.IsOwnDragColumn(ColumnIndex))
        {
            DragState.ResetColumn();
            return;
        }

        var sourceIndex = DragState.SourceColumnIndex;
        var sourceId = DragState.SourceColumnId ?? Column.Id;

        // Reset BEFORE invoking the consumer callback so re-entrant drops don't
        // see a stale source index, and so a faulting consumer can't leave the
        // grid in a "drag in progress" state.
        DragState.ResetColumn();

        if (sourceIndex < 0 || sourceIndex == ColumnIndex) return;

        var args = new ColumnReorderEventArgs(sourceId, sourceIndex, ColumnIndex);
        await OnColumnReorder.InvokeAsync(args);
    }

    public async ValueTask DisposeAsync()
    {
        if (_resizeRegistered)
        {
            try
            {
                await Interop.UnregisterColumnResize(_resizeHandleId);
            }
            catch (JSDisconnectedException) { }
        }
        if (_filterPositionRegistered)
        {
            await CleanupFilterPosition();
        }
    }
}

using Lumeo.Services;

namespace Lumeo;

internal sealed class DataGridLayoutService : IDisposable
{
    private readonly ComponentInteropService _interop;
    private readonly Action<Exception>? _onError;
    private System.Threading.Timer? _autoSaveTimer;
    private int _saveGeneration;
    private bool _layoutLoaded;
    private DataGridLayout? _defaultLayout;

    internal DataGridLayoutService(ComponentInteropService interop, Action<Exception>? onError = null)
    {
        _interop = interop;
        _onError = onError;
    }

    internal bool LayoutLoaded => _layoutLoaded;
    internal DataGridLayout? DefaultLayout { get => _defaultLayout; set => _defaultLayout = value; }

    internal async Task LoadPersistedLayoutAsync(string key, Func<DataGridLayout, Task> applyAction)
    {
        if (_layoutLoaded) return;
        try
        {
            var json = await _interop.LoadFromLocalStorage(key);
            if (!string.IsNullOrEmpty(json))
            {
                var layout = System.Text.Json.JsonSerializer.Deserialize<DataGridLayout>(json);
                if (layout is not null)
                {
                    _layoutLoaded = true;
                    await applyAction(layout);
                }
            }
        }
        catch (Exception ex) { Console.Error.WriteLine($"[Lumeo DataGrid] Failed to load persisted layout: {ex.Message}"); _onError?.Invoke(ex); }
    }

    internal async Task PersistAsync(string key, DataGridLayout layout, int? generation = null)
    {
        // If a generation is provided, only persist if it's still current
        if (generation.HasValue && generation.Value != _saveGeneration) return;
        try
        {
            var json = System.Text.Json.JsonSerializer.Serialize(layout);
            await _interop.SaveToLocalStorage(key, json);
        }
        catch (Exception ex) { Console.Error.WriteLine($"[Lumeo DataGrid] Failed to save layout: {ex.Message}"); _onError?.Invoke(ex); }
    }

    internal async Task ClearPersistedAsync(string key)
    {
        try { await _interop.RemoveFromLocalStorage(key); }
        catch (Exception ex) { Console.Error.WriteLine($"[Lumeo DataGrid] Failed to clear persisted layout: {ex.Message}"); _onError?.Invoke(ex); }
    }

    internal async Task<List<DataGridNamedLayout>> GetPersonalLayoutsAsync(string key)
    {
        try
        {
            var json = await _interop.LoadFromLocalStorage(key);
            if (!string.IsNullOrEmpty(json))
                return System.Text.Json.JsonSerializer.Deserialize<List<DataGridNamedLayout>>(json) ?? new();
        }
        catch (Exception ex) { Console.Error.WriteLine($"[Lumeo DataGrid] Failed to load named layouts: {ex.Message}"); _onError?.Invoke(ex); }
        return new();
    }

    internal async Task SaveNamedLayoutsAsync(string key, List<DataGridNamedLayout> layouts)
    {
        try
        {
            var json = System.Text.Json.JsonSerializer.Serialize(layouts);
            await _interop.SaveToLocalStorage(key, json);
        }
        catch (Exception ex) { Console.Error.WriteLine($"[Lumeo DataGrid] Failed to save named layouts: {ex.Message}"); _onError?.Invoke(ex); }
    }

    internal int CurrentSaveGeneration => _saveGeneration;

    internal void ScheduleAutoSave(Func<Task> persistCallback)
    {
        _autoSaveTimer?.Dispose();
        ++_saveGeneration;
        _autoSaveTimer = new System.Threading.Timer(_ =>
        {
            _ = Task.Run(async () =>
            {
                try { await persistCallback(); }
                catch (Exception ex) { Console.Error.WriteLine($"[Lumeo DataGrid] Autosave failed: {ex.Message}"); }
            });
        }, null, 500, System.Threading.Timeout.Infinite);
    }

    public void Dispose()
    {
        _autoSaveTimer?.Dispose();
    }
}

@namespace Lumeo
@typeparam TItem
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (Context is not null)
{
    <div data-slot="datagrid-pagination" class="@CssClass" @attributes="AdditionalAttributes">
        @if (PageSizeOptions is { Length: > 0 })
        {
            <div class="flex items-center gap-2 text-sm text-muted-foreground whitespace-nowrap">
                <span class="text-xs">@L["Pagination.RowsPerPage"]</span>
                <Select Value="@Context.PageSize.ToString()" ValueChanged="@OnPageSizeSelected">
                    <SelectTrigger Class="h-8 w-[70px]">
                        <span class="text-sm">@Context.PageSize</span>
                    </SelectTrigger>
                    <SelectContent>
                        @foreach (var size in PageSizeOptions)
                        {
                            <SelectItem Value="@size.ToString()">@size</SelectItem>
                        }
                    </SelectContent>
                </Select>
            </div>
        }

        <div class="ml-auto flex items-center gap-4 text-sm text-muted-foreground whitespace-nowrap">
            <span class="tabular-nums">@L["Pagination.RangeOfTotal", StartItem, EndItem, Context.TotalCount]</span>
            <Pagination Class="!mx-0 !w-auto">
                <PaginationContent>
                    <PaginationPrevious OnClick="@GoToPrevious" Disabled="@(Context.CurrentPage <= 1)" />
                    @foreach (var page in GetPageNumbers())
                    {
                        if (page == -1)
                        {
                            <PaginationEllipsis />
                        }
                        else
                        {
                            var pageNum = page;
                            <PaginationItem IsActive="@(pageNum == Context.CurrentPage)" OnClick="@(() => GoToPage(pageNum))">
                                @(pageNum)
                            </PaginationItem>
                        }
                    }
                    <PaginationNext OnClick="@GoToNext" Disabled="@(Context.CurrentPage >= TotalPages)" />
                </PaginationContent>
            </Pagination>
        </div>
    </div>
}

@code {
    [CascadingParameter] private DataGridContext<TItem>? Context { get; set; }
    [Parameter] public EventCallback<int> PageChanged { get; set; }
    [Parameter] public EventCallback<int> PageSizeChanged { get; set; }
    /// <summary>Page-size options shown in the rows-per-page selector.
    /// Empty array hides the selector entirely.</summary>
    [Parameter] public int[] PageSizeOptions { get; set; } = new[] { 10, 25, 50, 100 };
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex flex-wrap items-center gap-3 px-4 py-3 border-t border-border/40 {Class}".Trim();

    private int TotalPages => Context is not null && Context.PageSize > 0
        ? Math.Max(1, (int)Math.Ceiling((double)Context.TotalCount / Context.PageSize))
        : 1;

    private int StartItem => Context is not null && Context.TotalCount > 0
        ? (Context.CurrentPage - 1) * Context.PageSize + 1
        : 0;

    private int EndItem => Context is not null
        ? Math.Min(Context.CurrentPage * Context.PageSize, Context.TotalCount)
        : 0;

    private async Task GoToPage(int page)
    {
        await PageChanged.InvokeAsync(page);
    }

    private async Task GoToPrevious()
    {
        if (Context is not null && Context.CurrentPage > 1)
        {
            await PageChanged.InvokeAsync(Context.CurrentPage - 1);
        }
    }

    private async Task GoToNext()
    {
        if (Context is not null && Context.CurrentPage < TotalPages)
        {
            await PageChanged.InvokeAsync(Context.CurrentPage + 1);
        }
    }

    private async Task OnPageSizeSelected(string value)
    {
        if (int.TryParse(value, out var size))
        {
            await PageSizeChanged.InvokeAsync(size);
        }
    }

    private List<int> GetPageNumbers()
    {
        var pages = new List<int>();
        var total = TotalPages;
        var current = Context?.CurrentPage ?? 1;

        if (total <= 7)
        {
            for (var i = 1; i <= total; i++) pages.Add(i);
        }
        else
        {
            pages.Add(1);
            if (current > 3) pages.Add(-1); // ellipsis
            var start = Math.Max(2, current - 1);
            var end = Math.Min(total - 1, current + 1);
            for (var i = start; i <= end; i++) pages.Add(i);
            if (current < total - 2) pages.Add(-1); // ellipsis
            pages.Add(total);
        }

        return pages;
    }
}

@namespace Lumeo
@typeparam TItem
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<tr data-slot="datagrid-row" class="group/row @CssClass" style="@RowStyleString"
    role="row"
    aria-rowindex="@AriaRowIndex"
    aria-level="@AriaLevel"
    aria-expanded="@AriaExpanded"
    aria-selected="@(Context?.SelectionMode != DataGridSelectionMode.None ? (IsSelected ? "true" : "false") : null)"
    @onclick="HandleClick"
    @ondblclick="HandleDoubleClick"
    @oncontextmenu="HandleContextMenu"
    @oncontextmenu:preventDefault="@(Context?.RowContextMenuEnabled ?? false)"
    draggable="@(Context?.RowReorderable == true ? "true" : "false")"
    @ondragstart="HandleDragStart"
    @ondragover:preventDefault="true"
    @ondrop="HandleDrop"
    @attributes="AdditionalAttributes">

    @* Row drag handle *@
    @if (Context?.RowReorderable == true)
    {
        <td role="gridcell" class="px-1 py-2 w-8 cursor-grab active:cursor-grabbing" @onclick:stopPropagation="true">
            <Blazicon Svg="Lucide.GripVertical" class="h-4 w-4 text-muted-foreground/60" />
        </td>
    }

    @if (Context?.SelectionMode == DataGridSelectionMode.Multiple)
    {
        @* When any column is pinned left, the selection cell must also be sticky at
           left:0 so it stays visible during horizontal scroll and doesn't slide
           behind the pinned data column. Matches the z-index of DataGridHeaderCell
           pinned headers (z-20 on thead, z-10 on body cells). *@
        @* stopPropagation is required: without it, clicking the checkbox toggles
           selection (via OnCheckChanged) AND the click bubbles to <tr>'s HandleClick
           which toggles selection again — net no-op. The single-select cell below
           already does this on its <button>. *@
        <td role="gridcell" class="@(Context.HasPinnedLeft ? "px-3 py-2 w-10 sticky left-0 z-10 group-hover/row:bg-muted/50" : "px-3 py-2 w-10")" style="@SelectionPinStyle"
            @onclick:stopPropagation="true">
            <Checkbox Checked="@IsSelected" CheckedChanged="@OnCheckChanged" />
        </td>
    }
    else if (Context?.SelectionMode == DataGridSelectionMode.Single)
    {
        <td role="gridcell" class="@(Context.HasPinnedLeft ? "px-3 py-2 w-10 sticky left-0 z-10 group-hover/row:bg-muted/50" : "px-3 py-2 w-10")" style="@SelectionPinStyle">
            <button type="button"
                    class="h-4 w-4 rounded-full border border-primary @(IsSelected ? "bg-primary" : "bg-background")"
                    @onclick="@(() => Context?.ToggleSelection(Item))"
                    @onclick:stopPropagation="true">
                @if (IsSelected)
                {
                    <span class="block h-2 w-2 mx-auto rounded-full bg-primary-foreground"></span>
                }
            </button>
        </td>
    }

    @if (HasDetailTemplate)
    {
        <td role="gridcell" class="px-1 py-2 w-8">
            <button type="button"
                    class="inline-flex items-center justify-center h-6 w-6 rounded hover:bg-muted transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                    @onclick="ToggleExpand"
                    @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ChevronDown" class="@DetailChevronClasses" />
            </button>
        </td>
    }

    @if (Context is not null)
    {
        @if (IsEditing)
        {
            @foreach (var column in Context.VisibleColumns)
            {
                <td @key="column.Id" role="gridcell" class="px-3 py-2 text-sm">
                    @if (column.EditTemplate is not null)
                    {
                        var editCtx = new CellEditContext<TItem>
                        {
                            Item = Item,
                            Column = column,
                            Value = Context.GetEditValue(Item, column),
                            ValueChanged = () => StateHasChanged()
                        };
                        @column.EditTemplate(editCtx)
                    }
                    else
                    {
                        <input class="w-full h-7 rounded border border-input bg-background px-2 text-sm focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                               value="@(Context.GetEditValue(Item, column)?.ToString() ?? "")"
                               @oninput="@(e => Context.SetEditValue(Item, column, e.Value?.ToString()))" />
                    }
                </td>
            }
            @* Save / Cancel buttons cell *@
            <td role="gridcell" class="px-3 py-2 text-sm w-24">
                <div class="flex items-center gap-1">
                    <Tooltip>
                        <TooltipTrigger AsChild>
                            <ChildContentSlot Context="slot">
                                <button type="button"
                                        class="inline-flex items-center justify-center h-6 w-6 rounded bg-primary text-primary-foreground hover:bg-primary/90 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                                        aria-label="@L["DataGrid.CommitEdit"]"
                                        @onclick="SaveRowEdit"
                                        @onclick:stopPropagation="true"
                                        @attributes="slot.Attributes">
                                    <Blazicon Svg="Lucide.Check" class="h-3.5 w-3.5" />
                                </button>
                            </ChildContentSlot>
                        </TooltipTrigger>
                        <TooltipContent>@L["DataGrid.CommitEdit"]</TooltipContent>
                    </Tooltip>
                    <Tooltip>
                        <TooltipTrigger AsChild>
                            <ChildContentSlot Context="slot">
                                <button type="button"
                                        class="inline-flex items-center justify-center h-6 w-6 rounded border border-border/40 hover:bg-muted focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                                        aria-label="@L["DataGrid.CancelEdit"]"
                                        @onclick="CancelRowEdit"
                                        @onclick:stopPropagation="true"
                                        @attributes="slot.Attributes">
                                    <Blazicon Svg="Lucide.X" class="h-3.5 w-3.5" />
                                </button>
                            </ChildContentSlot>
                        </TooltipTrigger>
                        <TooltipContent>@L["DataGrid.CancelEdit"]</TooltipContent>
                    </Tooltip>
                </div>
            </td>
        }
        else
        {
            var colIdx = 0;
            var leadingCols = LeadingColumnCount;
            @foreach (var column in Context.VisibleColumns)
            {
                var ci = colIdx;
                <DataGridCell @key="column.Id" TItem="TItem" Item="Item" Column="column"
                              RowIndex="RowIndex"
                              ColumnIndex="ci"
                              AriaColIndex="@(leadingCols + ci + 1)"
                              Navigable="@(!Context.IsGrouped && Context.GroupTree is null && !Context.IsTreeGrid)" />
                colIdx++;
            }
            @if (Context.EditMode == DataGridEditMode.Row)
            {
                <td role="gridcell" class="px-3 py-2 text-sm w-10">
                    <Tooltip>
                        <TooltipTrigger AsChild>
                            <ChildContentSlot Context="slot">
                                <button type="button"
                                        class="inline-flex items-center justify-center h-6 w-6 rounded hover:bg-muted transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                                        aria-label="@L["DataGrid.Edit"]"
                                        @onclick="StartRowEdit"
                                        @onclick:stopPropagation="true"
                                        @attributes="slot.Attributes">
                                    <Blazicon Svg="Lucide.Pencil" class="h-3.5 w-3.5 text-muted-foreground" />
                                </button>
                            </ChildContentSlot>
                        </TooltipTrigger>
                        <TooltipContent>@L["DataGrid.Edit"]</TooltipContent>
                    </Tooltip>
                </td>
            }
        }
    }
</tr>

@if (IsExpanded && DetailTemplate is not null)
{
    <DataGridDetailRow TItem="TItem" Item="Item" DetailTemplate="DetailTemplate" ColSpan="@ColSpan" />
}

@code {
    [CascadingParameter] private DataGridContext<TItem>? Context { get; set; }
    [CascadingParameter] private DataGrid<TItem>? ParentGrid { get; set; }
    [CascadingParameter] private DataGridDragState? DragStateCtx { get; set; }
    [Parameter] public TItem Item { get; set; } = default!;
    [Parameter] public int RowIndex { get; set; }
    [Parameter] public RenderFragment<TItem>? DetailTemplate { get; set; }
    [Parameter] public EventCallback<(TItem, double, double)> OnContextMenu { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsSelected => Context?.IsRowSelected(Item) ?? false;
    private bool IsExpanded => Context?.IsRowExpanded(Item) ?? false;
    private bool IsEditing => Context?.IsRowEditing(Item) ?? false;
    private bool HasDetailTemplate => DetailTemplate is not null;

    // Single ChevronDown that rotates -90deg when collapsed; smooth like Accordion.
    private string DetailChevronClasses =>
        $"h-4 w-4 shrink-0 text-muted-foreground transition-transform duration-200{(IsExpanded ? "" : " -rotate-90")}";

    // 1-based ARIA row index. The header normally occupies row 1, so body rows start at 2.
    // When DataGridColumnGroups are declared the header is a 2-row block (parent labels +
    // data-column row) and body rows must start at 3 — otherwise the first body row reports
    // the same aria-rowindex the data-header already uses, giving assistive tech duplicate
    // row positions.
    private int AriaRowIndex => RowIndex + (Context?.ColumnGroups.Count > 0 ? 3 : 2);

    // ARIA tree-grid attributes — only meaningful when IsTreeGrid is true.
    private int? AriaLevel => (Context?.IsTreeGrid == true) ? (Context.TreeLevelOf(Item) + 1) : null;
    private string? AriaExpanded => (Context?.IsTreeGrid == true) ? (IsExpanded ? "true" : "false") : null;

    /// <summary>Count of non-data leading columns rendered before the first data
    /// cell (drag handle, selection, detail toggle). Mirrors DataGridHeader so
    /// aria-colindex values line up between header and body.</summary>
    private int LeadingColumnCount
    {
        get
        {
            var n = 0;
            if (Context?.RowReorderable == true) n++;
            if (Context?.SelectionMode != DataGridSelectionMode.None) n++;
            if (HasDetailTemplate) n++;
            return n;
        }
    }

    private int ColSpan
    {
        get
        {
            var count = Context?.VisibleColumns.Count ?? 0;
            if (Context?.SelectionMode != DataGridSelectionMode.None) count++;
            if (HasDetailTemplate) count++;
            if (Context?.RowReorderable == true) count++;
            if (Context?.EditMode == DataGridEditMode.Row) count++;
            return count;
        }
    }

    // Memoization: at 1k rows × N renders, allocating the joined class string
    // every access is measurable. We hash the inputs that influence the result
    // into a value tuple and return the cached string when the key matches.
    // Under-caching is safe (we recompute, same as before); over-caching would
    // be a regression — every input that mutates the output participates in the key.
    private (object Key, string Css)? _cssCache;

    private string CssClass
    {
        get
        {
            var custom = Context?.RowClass?.Invoke(Item);
            var key = (RowIndex, IsSelected, IsEditing, custom, Class);
            if (_cssCache is { } c && c.Key.Equals(key)) return c.Css;

            var css = string.Join(" ", new[]
            {
                "border-b border-border/40 transition-colors hover:bg-muted/50",
                IsSelected ? "bg-primary/5" : null,
                IsEditing ? "bg-muted/20" : null,
                custom,
                Class
            }.Where(s => !string.IsNullOrWhiteSpace(s)));
            _cssCache = (key, css);
            return css;
        }
    }

    private string? RowStyleString => Context?.RowStyle?.Invoke(Item);

    // Opaque background for the sticky-left selection cell so it doesn't show
    // scrolling content through, while preserving the row's stripe pattern when
    // Striped=true (Tailwind v4 can't generate arbitrary classes built via
    // C# string interpolation — inline color-mix is the reliable path).
    private string SelectionPinStyle
    {
        get
        {
            if (Context?.HasPinnedLeft != true) return string.Empty;
            return (Context?.Striped == true && RowIndex % 2 == 1)
                ? "background-color: color-mix(in srgb, var(--color-card) 70%, var(--color-muted));"
                : "background-color: var(--color-card);";
        }
    }

    private async Task HandleClick()
    {
        if (Context is not null)
        {
            if (Context.SelectionMode != DataGridSelectionMode.None)
            {
                Context.ToggleSelection(Item);
            }
            await Context.OnRowClick.InvokeAsync(Item);
        }
    }

    private async Task HandleDoubleClick()
    {
        if (Context is not null)
        {
            await Context.OnRowDoubleClick.InvokeAsync(Item);
        }
    }

    private async Task HandleContextMenu(MouseEventArgs e)
    {
        if (Context is not null && OnContextMenu.HasDelegate)
        {
            await OnContextMenu.InvokeAsync((Item, e.ClientX, e.ClientY));
        }
    }

    private void ToggleExpand()
    {
        Context?.ToggleRowExpand(Item);
    }

    private async Task OnCheckChanged(bool value)
    {
        Context?.ToggleSelection(Item);
    }

    // --- Row Editing ---

    private void StartRowEdit()
    {
        Context?.StartRowEdit(Item);
    }

    private async Task SaveRowEdit()
    {
        if (Context is not null)
            await Context.CommitRowEdit(Item);
    }

    private void CancelRowEdit()
    {
        Context?.CancelRowEdit(Item);
    }

    // --- Row Drag & Drop ---
    //
    // Drag state is held by an instance-bound DataGridDragState cascaded from
    // the owning DataGrid<TItem> (see DataGridHeaderCell for the column drag
    // counterpart). This replaces the previous static-class holder which was
    // process-global; cross-grid drops were applied to the wrong grid. The
    // drop handler now verifies the drag originated in this grid via
    // DragStateCtx.IsOwnDragRow().

    private void HandleDragStart(DragEventArgs e)
    {
        if (DragStateCtx is null) return;
        DragStateCtx.StartRowDrag(RowIndex);
    }

    private void HandleDrop(DragEventArgs e)
    {
        if (DragStateCtx is null) return;

        // Reject cross-grid drops — only honor drags that originated in our owning grid.
        if (!DragStateCtx.IsOwnDragRow())
        {
            DragStateCtx.ResetRow();
            return;
        }

        var sourceIndex = DragStateCtx.SourceRowIndex;
        DragStateCtx.ResetRow();

        if (sourceIndex < 0 || sourceIndex == RowIndex) return;
        ParentGrid?.MoveRow(sourceIndex, RowIndex);
    }
}

using System.Runtime.CompilerServices;

namespace Lumeo;

/// <summary>
/// Stable row-key resolver for <see cref="DataGridBody{TItem}"/>.
/// <para>
/// Blazor's <c>@key</c> dedupes siblings via <see cref="object.Equals(object?)"/>.
/// When <c>TItem</c> is a <see langword="record"/> (value-equality) and two
/// instances happen to be equal — e.g. two freshly-added "blank" rows from a
/// playground or a default-shaped row template — the framework throws
/// <c>InvalidOperationException: More than one sibling … has the same key
/// value</c> and unmounts the tree.
/// </para>
/// <para>
/// For reference types we return <see cref="RuntimeHelpers.GetHashCode(object)"/>,
/// which is the runtime's identity hash — stable per instance regardless of
/// any <c>Equals</c> override. For value types we return the boxed item itself
/// (no instance identity exists), which preserves the original behaviour.
/// </para>
/// </summary>
internal static class DataGridRowKeys
{
    public static object KeyFor<T>(T item)
    {
        if (item is null) return Unset;
        if (typeof(T).IsValueType) return item;
        return RuntimeHelpers.GetHashCode(item);
    }

    private static readonly object Unset = new();
}

