                       placeholder="@L["DataGrid.SearchPlaceholder"]"
                       class="h-8 w-full max-w-56 min-w-0 rounded-md border border-input bg-transparent pl-8 pr-3 text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                       value="@SearchText"
                       @oninput="OnSearchInput" />
            </div>
        }

        @if (RegisteredContent?.ChildContent is not null)
        {
            @RegisteredContent.ChildContent
        }

        @if (Context is not null)
        {
            @foreach (var filter in Context.Filters)
            {
                <div class="flex items-center gap-1 rounded-full bg-muted px-2.5 py-1 text-xs">
                    <span class="font-medium">@filter.Field</span>
